# Custom instrumented database operations
def execute_query(query, params=(), fetch=False):
    with capture_span('db.query', span_type='db', span_subtype='sqlite', labels={'query': query}):
        conn = sqlite3.connect(DB_PATH)
        conn.row_factory = sqlite3.Row
        cursor = conn.cursor()
        
        # Capture SQL query details
        elasticapm.label(sql_query=query, sql_params=str(params))
        
        start_time = time.time()
        cursor.execute(query, params)
        
        if fetch:
            result = cursor.fetchall()
            conn.close()
            
            # Add custom metrics
            elasticapm.label(rows_returned=len(result), query_time=time.time() - start_time)
            return [dict(row) for row in result]
        else:
            conn.commit()
            last_id = cursor.lastrowid
            conn.close()
            
            # Add custom metrics
            elasticapm.label(rows_affected=cursor.rowcount, query_time=time.time() - start_time)
            return last_id

