@capture_span('business.calculate_total')
def calculate_order_total(items):
    elasticapm.label(item_count=len(items))
    total = 0
    for item in items:
        time.sleep(0.01)  # Simulate processing time
        total += item.get('price', 0) * item.get('quantity', 1)
    
    elasticapm.label(total_amount=total)
    return total

@capture_span('business.validate_user')
def validate_user_data(username, email):
    elasticapm.label(username=username, email=email)
    
    if not username or len(username) < 3:
        raise ValueError("Username must be at least 3 characters")
    
    if '@' not in email:
        raise ValueError("Invalid email format")
    
    return True

