@app.before_request
def before_request():
    request.start_time = time.time()
    elasticapm.label(
        method=request.method,
        path=request.path,
        remote_addr=request.remote_addr,
        user_agent=request.headers.get('User-Agent', '')
    )

@app.after_request
def after_request(response):
    if hasattr(request, 'start_time'):
        duration = time.time() - request.start_time
        elasticapm.label(
            response_status=response.status_code,
            request_duration=duration,
            content_length=response.content_length
        )
    return response

# Manual transaction and span creation example
def perform_complex_task(task_id):
    client = elasticapm.get_client()
    
    client.begin_transaction('background_task')
    elasticapm.label(task_id=task_id, task_type='complex')
    
    try:
        with capture_span('task_step_1', span_type='custom'):
            time.sleep(0.1)
            elasticapm.label(step=1, status='completed')
        
        with capture_span('task_step_2', span_type='custom'):
            time.sleep(0.1)
            elasticapm.label(step=2, status='completed')
        
        client.end_transaction('background_task', 'success')
    except Exception as e:
        client.capture_exception()
        client.end_transaction('background_task', 'failure')
        raise

